// Başlanğıc mətbəx obyekti
let kitchen = {
  chefName: "Aysel",
  dish: "Omlet",
  tool: "tava"
};

// 1. Object.keys: Obyektin açarlarını qaytarır
console.log(Object.keys(kitchen)); // nəticə: ["chefName", "dish", "tool"]

// 2. Object.values: Obyektin dəyərlərini qaytarır
console.log(Object.values(kitchen)); // nəticə: ["Aysel", "Omlet", "tava"]

// 3. Object.entries: Açar-dəyər cütlərini qaytarır
console.log(Object.entries(kitchen)); // nəticə: [["chefName", "Aysel"], ["dish", "Omlet"], ["tool", "tava"]]

// 4. Object.assign: Obyektləri birləşdirir
let newTools = { spoon: "böyük" };
Object.assign(kitchen, newTools);
console.log(kitchen); // nəticə: { chefName: "Aysel", dish: "Omlet", tool: "tava", spoon: "böyük" }

// 5. Object.create: Prototipdən yeni obyekt yaradır
let protoKitchen = { cook: function() { return "Yemək hazır!"; } };
let newKitchen = Object.create(protoKitchen);
newKitchen.chefName = "Elvin";
console.log(newKitchen.cook()); // nəticə: Yemək hazır!

// 6. Object.defineProperty: Obyektə yeni xüsusiyyət təyin edir
Object.defineProperty(kitchen, "oven", {
  value: "elektrik",
  writable: true
});
console.log(kitchen.oven); // nəticə: elektrik

// 7. Object.defineProperties: Bir neçə xüsusiyyət təyin edir
Object.defineProperties(kitchen, {
  stove: { value: "qaz", writable: true },
  fridge: { value: "böyük", writable: false }
});
console.log(kitchen.stove, kitchen.fridge); // nəticə: qaz, böyük

// 8. Object.getOwnPropertyDescriptor: Xüsusiyyətin təsvirini qaytarır
let descriptor = Object.getOwnPropertyDescriptor(kitchen, "fridge");
console.log(descriptor); // nəticə: { value: "böyük", writable: false, enumerable: true, configurable: true }

// 9. Object.getOwnPropertyDescriptors: Bütün xüsusiyyətlərin təsvirini qaytarır
console.log(Object.getOwnPropertyDescriptors(kitchen));
// nəticə: Obyektin bütün xüsusiyyətlərinin təsviri

// 10. Object.getPrototypeOf: Obyektin prototipini qaytarır
let proto = Object.getPrototypeOf(newKitchen);
console.log(proto.cook()); // nəticə: Yemək hazır!

// 11. Object.setPrototypeOf: Obyektin prototipini dəyişdirir
let anotherProto = { serve: function() { return "Yemək süfrəyə verilir!"; } };
Object.setPrototypeOf(newKitchen, anotherProto);
console.log(newKitchen.serve()); // nəticə: Yemək süfrəyə verilir!

// 12. Object.is: İki dəyərin eyni olub-olmadığını yoxlayır
console.log(Object.is(kitchen.dish, "Omlet")); // nəticə: true

// 13. Object.freeze: Obyekti dondurur (dəyişikliklərə qapalı edir)
Object.freeze(kitchen);
kitchen.dish = "Pancake"; // dəyişmir
console.log(kitchen.dish); // nəticə: Omlet

// 14. Object.seal: Obyekti möhürləyir (yeni xüsusiyyət əlavə edilmir, amma dəyərlər dəyişə bilər)
let sealedKitchen = { chefName: "Elvin", dish: "Tost" };
Object.seal(sealedKitchen);
sealedKitchen.dish = "Pancake"; // dəyişir
sealedKitchen.tool = "tava"; // əlavə olunmur
console.log(sealedKitchen); // nəticə: { chefName: "Elvin", dish: "Pancake" }

// 15. Object.preventExtensions: Obyektə yeni xüsusiyyətlər əlavə etməyi qadağan edir
let extKitchen = { chefName: "Aysel" };
Object.preventExtensions(extKitchen);
extKitchen.dish = "Omlet"; // əlavə olunmur
console.log(extKitchen); // nəticə: { chefName: "Aysel" }

// 16. Object.isFrozen: Obyektin dondurulub-dondurulmadığını yoxlayır
console.log(Object.isFrozen(kitchen)); // nəticə: true

// 17. Object.isSealed: Obyektin möhürlənib-möhürlənmədiyini yoxlayır
console.log(Object.isSealed(sealedKitchen)); // nəticə: true

// 18. Object.isExtensible: Obyektin genişləndirilə biləcəyini yoxlayır
console.log(Object.isExtensible(extKitchen)); // nəticə: false

