// Starting kitchen object
let kitchen = {
  chefName: "Aysel",
  dish: "Omelette",
  tool: "pan"
};

// 1. Object.keys: Returns the object’s keys
console.log(Object.keys(kitchen)); // Output: ["chefName", "dish", "tool"]

// 2. Object.values: Returns the object’s values
console.log(Object.values(kitchen)); // Output: ["Aysel", "Omelette", "pan"]

// 3. Object.entries: Returns key-value pairs
console.log(Object.entries(kitchen)); // Output: [["chefName", "Aysel"], ["dish", "Omelette"], ["tool", "pan"]]

// 4. Object.assign: Merges objects
let newTools = { spoon: "large" };
Object.assign(kitchen, newTools);
console.log(kitchen); // Output: { chefName: "Aysel", dish: "Omelette", tool: "pan", spoon: "large" }

// 5. Object.create: Creates a new object with a prototype
let protoKitchen = { cook: function() { return "Food is ready!"; } };
let newKitchen = Object.create(protoKitchen);
newKitchen.chefName = "Elvin";
console.log(newKitchen.cook()); // Output: Food is ready!

// 6. Object.defineProperty: Defines a new property
Object.defineProperty(kitchen, "oven", {
  value: "electric",
  writable: true
});
console.log(kitchen.oven); // Output: electric

// 7. Object.defineProperties: Defines multiple properties
Object.defineProperties(kitchen, {
  stove: { value: "gas", writable: true },
  fridge: { value: "large", writable: false }
});
console.log(kitchen.stove, kitchen.fridge); // Output: gas, large

// 8. Object.getOwnPropertyDescriptor: Returns a property’s descriptor
let descriptor = Object.getOwnPropertyDescriptor(kitchen, "fridge");
console.log(descriptor); // Output: { value: "large", writable: false, enumerable: true, configurable: true }

// 9. Object.getOwnPropertyDescriptors: Returns all property descriptors
console.log(Object.getOwnPropertyDescriptors(kitchen));
// Output: Descriptors for all properties

// 10. Object.getPrototypeOf: Returns the object’s prototype
let proto = Object.getPrototypeOf(newKitchen);
console.log(proto.cook()); // Output: Food is ready!

// 11. Object.setPrototypeOf: Sets the object’s prototype
let anotherProto = { serve: function() { return "Food is served!"; } };
Object.setPrototypeOf(newKitchen, anotherProto);
console.log(newKitchen.serve()); // Output: Food is served!

// 12. Object.is: Checks if two values are the same
console.log(Object.is(kitchen.dish, "Omelette")); // Output: true

// 13. Object.freeze: Freezes the object (no changes allowed)
Object.freeze(kitchen);
kitchen.dish = "Pancake"; // No change
console.log(kitchen.dish); // Output: Omelette

// 14. Object.seal: Seals the object (no new properties, but values can change)
let sealedKitchen = { chefName: "Elvin", dish: "Toast" };
Object.seal(sealedKitchen);
sealedKitchen.dish = "Pancake"; // Changes
sealedKitchen.tool = "pan"; // Not added
console.log(sealedKitchen); // Output: { chefName: "Elvin", dish: "Pancake" }

// 15. Object.preventExtensions: Prevents adding new properties
let extKitchen = { chefName: "Aysel" };
Object.preventExtensions(extKitchen);
extKitchen.dish = "Omelette"; // Not added
console.log(extKitchen); // Output: { chefName: "Aysel" }

// 16. Object.isFrozen: Checks if the object is frozen
console.log(Object.isFrozen(kitchen)); // Output: true

// 17. Object.isSealed: Checks if the object is sealed
console.log(Object.isSealed(sealedKitchen)); // Output: true

// 18. Object.isExtensible: Checks if the object is extensible
console.log(Object.isExtensible(extKitchen)); // Output: false

