// Начальный объект кухни
let kitchen = {
  chefName: "Айсель",
  dish: "Омлет",
  tool: "сковорода"
};

// 1. Object.keys: Возвращает ключи объекта
console.log(Object.keys(kitchen)); // Вывод: ["chefName", "dish", "tool"]

// 2. Object.values: Возвращает значения объекта
console.log(Object.values(kitchen)); // Вывод: ["Айсель", "Омлет", "сковорода"]

// 3. Object.entries: Возвращает пары ключ-значение
console.log(Object.entries(kitchen)); // Вывод: [["chefName", "Айсель"], ["dish", "Омлет"], ["tool", "сковорода"]]

// 4. Object.assign: Объединяет объекты
let newTools = { spoon: "большая" };
Object.assign(kitchen, newTools);
console.log(kitchen); // Вывод: { chefName: "Айсель", dish: "Омлет", tool: "сковорода", spoon: "большая" }

// 5. Object.create: Создаёт новый объект с прототипом
let protoKitchen = { cook: function() { return "Еда готова!"; } };
let newKitchen = Object.create(protoKitchen);
newKitchen.chefName = "Эльвин";
console.log(newKitchen.cook()); // Вывод: Еда готова!

// 6. Object.defineProperty: Определяет новое свойство
Object.defineProperty(kitchen, "oven", {
  value: "электрическая",
  writable: true
});
console.log(kitchen.oven); // Вывод: электрическая

// 7. Object.defineProperties: Определяет несколько свойств
Object.defineProperties(kitchen, {
  stove: { value: "газ", writable: true },
  fridge: { value: "большой", writable: false }
});
console.log(kitchen.stove, kitchen.fridge); // Вывод: газ, большой

// 8. Object.getOwnPropertyDescriptor: Возвращает описание свойства
let descriptor = Object.getOwnPropertyDescriptor(kitchen, "fridge");
console.log(descriptor); // Вывод: { value: "большой", writable: false, enumerable: true, configurable: true }

// 9. Object.getOwnPropertyDescriptors: Возвращает описания всех свойств
console.log(Object.getOwnPropertyDescriptors(kitchen));
// Вывод: Описания всех свойств

// 10. Object.getPrototypeOf: Возвращает прототип объекта
let proto = Object.getPrototypeOf(newKitchen);
console.log(proto.cook()); // Вывод: Еда готова!

// 11. Object.setPrototypeOf: Устанавливает прототип объекта
let anotherProto = { serve: function() { return "Еда подана!"; } };
Object.setPrototypeOf(newKitchen, anotherProto);
console.log(newKitchen.serve()); // Вывод: Еда подана!

// 12. Object.is: Проверяет, одинаковы ли два значения
console.log(Object.is(kitchen.dish, "Омлет")); // Вывод: true

// 13. Object.freeze: Замораживает объект (запрещает изменения)
Object.freeze(kitchen);
kitchen.dish = "Блины"; // Не изменяется
console.log(kitchen.dish); // Вывод: Омлет

// 14. Object.seal: Запечатывает объект (новые свойства не добавляются, значения можно менять)
let sealedKitchen = { chefName: "Эльвин", dish: "Тост" };
Object.seal(sealedKitchen);
sealedKitchen.dish = "Блины"; // Изменяется
sealedKitchen.tool = "сковорода"; // Не добавляется
console.log(sealedKitchen); // Вывод: { chefName: "Эльвин", dish: "Блины" }

// 15. Object.preventExtensions: Запрещает добавление новых свойств
let extKitchen = { chefName: "Айсель" };
Object.preventExtensions(extKitchen);
extKitchen.dish = "Омлет"; // Не добавляется
console.log(extKitchen); // Вывод: { chefName: "Айсель" }

// 16. Object.isFrozen: Проверяет, заморожен ли объект
console.log(Object.isFrozen(kitchen)); // Вывод: true

// 17. Object.isSealed: Проверяет, запечатан ли объект
console.log(Object.isSealed(sealedKitchen)); // Вывод: true

// 18. Object.isExtensible: Проверяет, можно ли расширять объект
console.log(Object.isExtensible(extKitchen)); // Вывод: false

